    68→function minifyCSS(css, isProperties = false) {
    69→        const placeholders = new Map();
    70→        let counter = 0;
    71→        let temp = css;
    72→        temp = temp.replace(/\$\{[^}]+\}/g, (match) => {
    73→                const key = `__PLACEHOLDER_${counter++}__`;
    74→                placeholders.set(key, match);
    75→                return key;
    76→        });
    77→
    78→        let minified;
    79→        if (isProperties) {
    80→                minified = temp
    81→                        .replace(/\/\*[\s\S]*?\*\//g, "") // Remove comments
    82→                        .replace(/\s+/g, " ") // Collapse whitespace
    83→                        .replace(/\s*([{};:,])\s*/g, "$1") // Remove spaces around punctuation
    84→                        .replace(/;\s*$/g, ";") // Clean up end
    85→                        .trim();
    86→        } else {
    87→                const result = lightningcss.transform({
    88→                        code: Buffer.from(temp),
    89→                        minify: true,
    90→                });
    91→                minified = result.code.toString();
    92→        }
    93→
    94→        for (const [key, value] of placeholders) {
    95→                minified = minified.replace(key, value);
    96→        }
    97→        return minified;
    98→}
