    10→// Utils
    11→
    12→async function refreshAccessToken(refreshToken) {
    13→        const res = await fetch("https://github.com/login/oauth/access_token", {
    14→                method: "POST",
    15→                headers: {
    16→                        "Content-Type": "application/json",
    17→                        Accept: "application/json",
    18→                },
    19→                body: JSON.stringify({
    20→                        client_id: GITHUB_CLIENT_ID,
    21→                        refresh_token: refreshToken,
    22→                        grant_type: "refresh_token",
    23→                }),
    24→        });
    25→
    26→        const data = await res.json();
    27→        if (data.error) {
    28→                const fatal = [
    29→                        "bad_refresh_token",
    30→                        "token_expired",
    31→                        "incorrect_client_credentials",
    32→                        "access_denied",
    33→                ];
    34→                const err = new Error(`Token refresh failed: ${data.error}`);
    35→                err.fatalToken = fatal.includes(data.error);
    36→                throw err;
    37→        }
    38→
    39→        return {
    40→                accessToken: data.access_token,
    41→                refreshToken: data.refresh_token || refreshToken,
    42→                expiresAt: Date.now() + (data.expires_in || 28800) * 1000,
    43→        };
    44→}
    45→
    46→async function checkRepoStarred(accessToken) {
    47→        const res = await fetch(
    48→                `https://api.github.com/user/starred/${REPO_OWNER}/${REPO_NAME}`,
    49→                {
    50→                        headers: {
    51→                                Authorization: `Bearer ${accessToken}`,
    52→                                Accept: "application/vnd.github+json",
    53→                                "X-GitHub-Api-Version": "2022-11-28",
    54→                        },
    55→                },
    56→        );
    57→
    58→        if (res.status === 401) throw new Error("401");
    59→        return res.status === 204;
    60→}
