    64→async function requestDeviceCodes() {
    65→        const res = await fetch("https://github.com/login/device/code", {
    66→                method: "POST",
    67→                headers: { "Content-Type": "application/json", Accept: "application/json" },
    68→                body: JSON.stringify({
