    81→async function pollForToken(deviceCode, intervalSec, expiresIn, onProgress) {
    82→        const deadline = Date.now() + expiresIn * 1000;
    83→        const pollMs = Math.max(intervalSec, 5) * 1000;
    84→
    85→        return new Promise((resolve, reject) => {
    86→                const tick = async () => {
    87→                        if (Date.now() >= deadline) {
    88→                                reject(new Error("expired"));
    89→                                return;
    90→                        }
    91→
    92→                        onProgress?.(Math.max(0, Math.round((deadline - Date.now()) / 1000)));
    93→
    94→                        try {
    95→                                const res = await fetch("https://github.com/login/oauth/access_token", {
    96→                                        method: "POST",
    97→                                        headers: {
    98→                                                "Content-Type": "application/json",
    99→                                                Accept: "application/json",
   100→                                        },
   101→                                        body: JSON.stringify({
   102→                                                client_id: GITHUB_CLIENT_ID,
   103→                                                device_code: deviceCode,
   104→                                                grant_type: "urn:ietf:params:oauth:grant-type:device_code",
   105→                                        }),
   106→                                });
   107→
   108→                                const data = await res.json();
   109→
   110→                                if (data.access_token) {
   111→                                        resolve({
   112→                                                accessToken: data.access_token,
   113→                                                refreshToken: data.refresh_token || null,
   114→                                                expiresAt: Date.now() + (data.expires_in || 28800) * 1000,
   115→                                        });
   116→                                        return;
   117→                                }
   118→
   119→                                switch (data.error) {
   120→                                        case "authorization_pending":
   121→                                                setTimeout(tick, pollMs);
   122→                                                break;
   123→                                        case "slow_down":
   124→                                                setTimeout(tick, pollMs + 5000);
   125→                                                break;
   126→                                        case "expired_token":
   127→                                                reject(new Error("expired"));
   128→                                                break;
   129→                                        case "access_denied":
   130→                                                reject(new Error("access_denied"));
   131→                                                break;
   132→                                        default:
   133→                                                reject(new Error(data.error || "unknown_poll_error"));
   134→                                }
   135→                        } catch (err) {
   136→                                reject(err);
   137→                        }
   138→                };
   139→
   140→                setTimeout(tick, pollMs);
   141→        });
   142→}
