   148→async function tryCheckGitHubStar() {
   149→        const config = loadConfig();
   150→        const github = config.github ?? {};
   151→        const accessToken = github.accessToken ?? null;
   152→        const refreshToken = github.refreshToken ?? null;
   153→
   154→        if (!accessToken) {
   155→                console.log("[GitHub Auth] No token found");
   156→                return { hasStarred: false, fatal: true };
   157→        }
   158→
   159→        try {
   160→                const hasStarred = await checkRepoStarred(accessToken);
   161→                console.log(`[GitHub Auth] Star: ${hasStarred ? "✔" : "❌"}`);
   162→                return { hasStarred };
   163→        } catch (err) {
   164→                if (err.message === "401" && refreshToken) {
   165→                        console.warn("[GitHub Auth] Token expired, attempting refresh...");
   166→                        try {
   167→                                const refreshed = await refreshAccessToken(refreshToken);
   168→                                config.github = {
   169→                                        accessToken: refreshed.accessToken,
   170→                                        refreshToken: refreshed.refreshToken,
   171→                                        expiresAt: refreshed.expiresAt,
   172→                                };
   173→                                saveConfig(config);
   174→                                console.log("[GitHub Auth] Token refreshed successfully");
   175→
   176→                                const hasStarred = await checkRepoStarred(refreshed.accessToken);
   177→                                console.log(`[GitHub Auth] Star: ${hasStarred ? "✔" : "❌"}`);
   178→                                return { hasStarred };
   179→                        } catch (refreshErr) {
   180→                                console.error(
   181→                                        "[GitHub Auth] Token refresh failed:",
   182→                                        refreshErr.message,
   183→                                );
   184→                                if (refreshErr.fatalToken) {
   185→                                        config.github.accessToken = null;
   186→                                        config.github.refreshToken = null;
   187→                                        saveConfig(config);
   188→                                        return { hasStarred: false, tokenExpired: true, fatal: true };
   189→                                }
   190→                                return { hasStarred: false, transient: true };
   191→                        }
   192→                }
   193→
   194→                if (err.message === "401") {
   195→                        console.warn("[GitHub Auth] Token expired or revoked.");
   196→                        return { hasStarred: false, tokenExpired: true, fatal: true };
   197→                }
   198→                console.error("[GitHub Auth] Check error:", err.message);
   199→                return { hasStarred: false, transient: true };
   200→        }
   201→}
