   203→export async function checkGitHubStar() {
   204→        const result = await tryCheckGitHubStar();
   205→        if (result.transient) {
   206→                console.warn("[GitHub Auth] Transient error, retrying in 10s...");
   207→                await sleep(10000);
   208→                return tryCheckGitHubStar();
   209→        }
   210→        return result;
   211→}
