    10→// Feed a Buffer into a writable stream in chunks, honoring backpressure so a
    11→// large input doesn't get buffered/flushed in one blocking write. Resolves once
    12→// fully written; rejects on stream error (e.g. EPIPE if ffmpeg exits early).
    13→function writeBufferToStream(stream, buffer, chunkSize = 64 * 1024) {
    14→        return new Promise((resolve, reject) => {
    15→                let offset = 0;
    16→
    17→                stream.on("error", reject);
    18→
    19→                function writeNext() {
    20→                        while (offset < buffer.length) {
    21→                                const end = Math.min(offset + chunkSize, buffer.length);
    22→                                const chunk = buffer.subarray(offset, end);
    23→                                offset = end;
    24→
    25→                                if (offset >= buffer.length) {
    26→                                        stream.end(chunk, resolve);
    27→                                        return;
    28→                                }
    29→
    30→                                if (!stream.write(chunk)) {
    31→                                        stream.once("drain", writeNext);
    32→                                        return;
    33→                                }
    34→                        }
    35→                }
    36→
    37→                writeNext();
    38→        });
    39→}
