    58→                                "mp3",
    59→                                "pipe:1",
    60→                        ]);
    61→
    62→                        const chunks = [];
    63→                        let duration = 0;
    64→
    65→                        ff.stdout.on("data", (c) => chunks.push(c));
    66→
    67→                        ff.stderr.on("data", (data) => {
    68→                                const s = data.toString();
    69→                                const dm = s.match(/Duration:\s*(\d{2}):(\d{2}):(\d{2}\.\d*)/);
    70→                                if (dm) duration = +dm[1] * 3600 + +dm[2] * 60 + +dm[3];
    71→                                const tm = s.match(/time=(\d{2}):(\d{2}):(\d{2}\.\d*)/);
    72→                                if (tm && duration > 0 && !sender.isDestroyed()) {
    73→                                        const cur = +tm[1] * 3600 + +tm[2] * 60 + +tm[3];
    74→                                        sender.send("nmc:convert-progress", Math.min(cur / duration, 0.99));
    75→                                }
    76→                        });
    77→
    78→                        ff.on("error", () => resolve(null));
    79→                        ff.on("close", (code) =>
    80→                                resolve(code === 0 && chunks.length ? Buffer.concat(chunks) : null),
    81→                        );
    82→
    83→                        // Errors here (e.g. EPIPE when ffmpeg exits early) are surfaced via
    84→                        // the 'error'/'close' handlers above, which settle the promise.
    85→                        writeBufferToStream(ff.stdin, Buffer.from(audioData)).catch(() => {});
    86→                });
    87→        });
    88→}
