   286→function pickAsset(release, type) {
   287→        const assets = release?.assets || [];
   288→        let ext;
   289→        if (type === "nsis") ext = ".exe";
   290→        else if (type === "pacman") ext = ".pkg.tar.zst";
   291→        else ext = ".deb";
