   295→function installSystemPackage(file, type) {
   296→        return new Promise((resolve, reject) => {
   297→                let args;
   298→                if (type === "pacman") {
   299→                        args = ["pacman", "-U", "--noconfirm", file];
   300→                } else {
   301→                        args = [
   302→                                "sh",
   303→                                "-c",
   304→                                `apt-get install -y "${file}" || { dpkg -i "${file}"; apt-get install -f -y; }`,
   305→                        ];
   306→                }
   307→
   308→                const child = spawn("pkexec", args, {
   309→                        stdio: ["ignore", "ignore", "pipe"],
   310→                });
   311→
   312→                let stderr = "";
   313→                child.stderr.on("data", (d) => (stderr += d.toString()));
   314→                child.on("error", reject);
   315→                child.on("close", (code) => {
   316→                        if (code === 0) resolve();
   317→                        else reject(new Error(`pkexec exited ${code}: ${stderr.trim()}`));
   318→                });
   319→        });
   320→}
