   322→function downloadFile(url, dest) {
   323→        return new Promise((resolve, reject) => {
   324→                const file = fs.createWriteStream(dest);
   325→                let lastTime = Date.now();
   326→                let lastBytes = 0;
   327→
   328→                function request(currentUrl) {
   329→                        https
   330→                                .get(
   331→                                        currentUrl,
   332→                                        { headers: { "User-Agent": "Next-Music-Updater" } },
   333→                                        (res) => {
   334→                                                if (
   335→                                                        res.statusCode >= 300 &&
   336→                                                        res.statusCode < 400 &&
   337→                                                        res.headers.location
   338→                                                ) {
   339→                                                        res.resume();
   340→                                                        request(res.headers.location);
   341→                                                        return;
   342→                                                }
   343→
   344→                                                if (res.statusCode !== 200) {
   345→                                                        res.resume();
   346→                                                        reject(new Error(`HTTP ${res.statusCode}`));
   347→                                                        return;
   348→                                                }
   349→
   350→                                                const total = Number(res.headers["content-length"]) || 0;
   351→                                                let transferred = 0;
   352→
   353→                                                res.on("data", (chunk) => {
   354→                                                        transferred += chunk.length;
   355→                                                        const now = Date.now();
   356→                                                        const dt = (now - lastTime) / 1000;
   357→                                                        if (dt >= 0.25) {
   358→                                                                sendToLoader("nmc-update:progress", {
   359→                                                                        percent: total ? (transferred / total) * 100 : 0,
   360→                                                                        transferred,
   361→                                                                        total,
   362→                                                                        bytesPerSecond: (transferred - lastBytes) / dt,
   363→                                                                });
   364→                                                                lastTime = now;
   365→                                                                lastBytes = transferred;
   366→                                                        }
   367→                                                });
   368→
   369→                                                res.pipe(file);
   370→                                                file.on("finish", () => {
   371→                                                        sendToLoader("nmc-update:progress", {
   372→                                                                percent: 100,
   373→                                                                transferred,
   374→                                                                total,
   375→                                                                bytesPerSecond: 0,
   376→                                                        });
   377→                                                        file.close(() => resolve());
   378→                                                });
   379→                                        },
   380→                                )
   381→                                .on("error", (err) => {
   382→                                        fs.unlink(dest, () => reject(err));
   383→                                });
   384→                }
   385→
   386→                file.on("error", (err) => {
   387→                        fs.unlink(dest, () => reject(err));
   388→                });
   389→
   390→                request(url);
   391→        });
   392→}
