   518→                        .get(url, { headers }, (res) => {
   519→                                let data = "";
   520→                                res.on("data", (chunk) => (data += chunk));
   521→                                res.on("end", () => {
   522→                                        const status = res.statusCode || 0;
   523→                                        if (status < 200 || status >= 300) {
   524→                                                reject(new Error(`HTTP ${status}`));
   525→                                                return;
   526→                                        }
   527→                                        try {
   528→                                                resolve(JSON.parse(data));
   529→                                        } catch (err) {
