   538→function isNewer(latestRaw, currentRaw) {
   539→        const latest = parseVersion(normalizeVersion(latestRaw));
   540→        const current = parseVersion(normalizeVersion(currentRaw));
   541→
   542→        if (!latest || !current) return false;
   543→
   544→        for (let i = 0; i < 3; i++) {
   545→                if (latest.base[i] > current.base[i]) return true;
   546→                if (latest.base[i] < current.base[i]) return false;
   547→        }
   548→
   549→        if (latest.beta === null && current.beta === null) return false;
   550→        if (latest.beta === null) return true; // stable > beta
   551→        if (current.beta === null) return false; // beta < stable
   552→        return latest.beta > current.beta;
   553→}
   554→
   555→function normalizeVersion(v) {
   556→        return String(v ?? "")
   557→                .trim()
   558→                .replace(/^v/, "");
   559→}
   560→
   561→function parseVersion(v) {
   562→        const beta = v.match(/^(\d+)\.(\d+)\.(\d+)-beta[.-]?(\d+)?$/);
   563→        if (beta) {
   564→                return {
   565→                        base: [Number(beta[1]), Number(beta[2]), Number(beta[3])],
   566→                        beta: Number(beta[4] ?? 0),
   567→                };
   568→        }
   569→        const stable = v.match(/^(\d+)\.(\d+)\.(\d+)$/);
   570→        if (stable) {
   571→                return {
   572→                        base: [Number(stable[1]), Number(stable[2]), Number(stable[3])],
   573→                        beta: null,
   574→                };
   575→        }
   576→        return null;
   577→}
