   147→                if (global.__nmcUpdateGate) {
   148→                        try {
   149→                                await global.__nmcUpdateGate;
   150→                        } catch {
   151→                                /* proceed regardless */
   152→                        }
   153→                }
   154→
   155→                closeLoaderWindow();
   156→
   157→                if (!startMinimized) mainWindow.show();
   158→        }
   159→
   160→        function injectApi() {
   161→                if (!cachedApiJs) {
   162→                        if (fs.existsSync(apiBundleFile)) {
   163→                                cachedApiJs = fs.readFileSync(apiBundleFile, "utf-8");
   164→                        } else {
   165→                                const parts = apiFunctionsOrder.map((name) =>
   166→                                        fs.readFileSync(path.join(apiFunctionsDir, `${name}.js`), "utf-8"),
   167→                                );
   168→                                const mainJs = fs.readFileSync(apiMainFile, "utf-8");
   169→                                cachedApiJs = `${parts.join("\n")}\n${mainJs}`;
   170→                        }
   171→                }
   172→                mainWindow.webContents
   173→                        .executeJavaScript(`(() => {\n${cachedApiJs}\n})()`)
   174→                        .catch(console.error);
   175→        }
   176→
   177→        function injectTitleBar() {
   178→                if (cachedTitleBarCss === null) {
   179→                        cachedTitleBarCss = fs.readFileSync(
   180→                                path.join(titlebarFolder, "titlebar.css"),
   181→                                "utf-8",
   182→                        );
   183→                }
   184→
   185→                if (cachedTitleBarJs === null) {
   186→                        cachedTitleBarJs = fs.readFileSync(
   187→                                path.join(titlebarFolder, "titlebar.js"),
   188→                                "utf-8",
   189→                        );
   190→                }
   191→
   192→                const css = cachedTitleBarCss;
   193→                const js = cachedTitleBarJs;
   194→
   195→                const showNextText =
   196→                        config.windowSettings?.titleBar?.nextText?.enable === true;
   197→                const showYandexMusicVersion =
   198→                        showNextText &&
   199→                        config.windowSettings?.titleBar?.nextText?.displayYandexMusicVersion ===
   200→                                true;
   201→
   202→                const titleBarConfig = {
   203→                        showNextText,
   204→                        showYandexMusicVersion,
   205→                        version: app.getVersion(),
   206→                };
   207→
   208→                mainWindow.webContents
   209→                        .executeJavaScript(
   210→                                `window.__nmcTitleBarConfig = ${JSON.stringify(titleBarConfig)};`,
   211→                        )
   212→                        .catch(console.error);
   213→
   214→                mainWindow.webContents.insertCSS(css).catch(console.error);
   215→                mainWindow.webContents.executeJavaScript(js).catch(console.error);
   216→        }
   217→
   218→        function closeLoaderWindow() {
   219→                if (!config.launchSettings.loaderWindow || !loaderWindow) return;
   220→
   221→                try {
   222→                        loaderWindow.close();
   223→                        loaderWindow = null;
   224→                } catch {
   225→                        console.log("Loader window is missing");
   226→                }
   227→        }
   228→
   229→        function onFailLoad(
   230→                event,
   231→                errorCode,
   232→                errorDescription,
   233→                validatedURL,
   234→                isMainFrame,
   235→        ) {
   236→                if (isMainFrame) {
   237→                        mainWindow.loadFile(
   238→                                __dirname,
   239→                                "../../../renderer/fallback/fallback.html",
   240→                        );
   241→                }
   242→        }
   243→
   244→        function setupInitialVisibility() {
   245→                if (config.launchSettings.startMinimized) {
